import{_ as s,C as B,o as r,c as n,a2 as E,b as i,w as a,a as e,E as l,a3 as o,j as d}from"./chunks/framework.Crpw6aS5.js";const m=JSON.parse('{"title":"CAP 理论与 BASE 理论","description":"","frontmatter":{"title":"CAP 理论与 BASE 理论","module":"distributed","difficulty":"advanced","interviewFrequency":"high","tags":["分布式系统","CAP","BASE","最终一致性","面试高频"],"codeExample":"05-distributed/distributed-examples/","relatedEntries":["/5-distributed/5.1-distributed/02-consensus","/4-middleware/4.5-registry/05-comparison"],"prerequisites":["/2-framework/2.3-springcloud/01-registry"],"estimatedTime":"45min"},"headers":[],"relativePath":"5-distributed/5.1-distributed/01-cap-base.md","filePath":"5-distributed/5.1-distributed/01-cap-base.md","lastUpdated":null}'),C={name:"5-distributed/5.1-distributed/01-cap-base.md"};function h(p,t,u,b,P,c){const A=B("Mermaid");return r(),n("div",null,[t[3]||(t[3]=E('<h1 id="cap-理论与-base-理论" tabindex="-1">CAP 理论与 BASE 理论 <a class="header-anchor" href="#cap-理论与-base-理论" aria-label="Permalink to &quot;CAP 理论与 BASE 理论&quot;">​</a></h1><h2 id="概念说明" tabindex="-1">概念说明 <a class="header-anchor" href="#概念说明" aria-label="Permalink to &quot;概念说明&quot;">​</a></h2><p>CAP 理论和 BASE 理论是分布式系统设计的两大基石。CAP 告诉我们分布式系统不可能同时满足一致性、可用性和分区容错性；BASE 则是对 CAP 中一致性和可用性权衡的实践总结，提出了&quot;最终一致性&quot;的思路。</p><h2 id="核心原理" tabindex="-1">核心原理 <a class="header-anchor" href="#核心原理" aria-label="Permalink to &quot;核心原理&quot;">​</a></h2><h3 id="一、cap-理论" tabindex="-1">一、CAP 理论 <a class="header-anchor" href="#一、cap-理论" aria-label="Permalink to &quot;一、CAP 理论&quot;">​</a></h3><p>CAP 理论由 Eric Brewer 在 2000 年提出，2002 年被 Seth Gilbert 和 Nancy Lynch 证明。</p><h4 id="cap-三要素" tabindex="-1">CAP 三要素 <a class="header-anchor" href="#cap-三要素" aria-label="Permalink to &quot;CAP 三要素&quot;">​</a></h4><table tabindex="0"><thead><tr><th>要素</th><th>英文</th><th>含义</th></tr></thead><tbody><tr><td>C</td><td>Consistency（一致性）</td><td>所有节点在同一时刻看到的数据一致（线性一致性）</td></tr><tr><td>A</td><td>Availability（可用性）</td><td>每个请求都能在合理时间内收到非错误响应</td></tr><tr><td>P</td><td>Partition Tolerance（分区容错性）</td><td>网络分区发生时系统仍能继续运行</td></tr></tbody></table><h4 id="为什么是-三选二" tabindex="-1">为什么是&quot;三选二&quot;？ <a class="header-anchor" href="#为什么是-三选二" aria-label="Permalink to &quot;为什么是&quot;三选二&quot;？&quot;">​</a></h4>',9)),(r(),i(o,null,{default:a(()=>[l(A,{id:"mermaid-74",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20Client%20as%20%E5%AE%A2%E6%88%B7%E7%AB%AF%0A%20%20%20%20participant%20N1%20as%20%E8%8A%82%E7%82%B91%0A%20%20%20%20participant%20N2%20as%20%E8%8A%82%E7%82%B92%0A%0A%20%20%20%20Note%20over%20N1%2CN2%3A%20%E7%BD%91%E7%BB%9C%E5%88%86%E5%8C%BA%E5%8F%91%E7%94%9F%EF%BC%88P%20%E5%BF%85%E9%A1%BB%E5%AE%B9%E5%BF%8D%EF%BC%89%0A%0A%20%20%20%20Client-%3E%3EN1%3A%20%E5%86%99%E5%85%A5%20X%3D1%0A%20%20%20%20N1-%3E%3EN1%3A%20%E6%9C%AC%E5%9C%B0%E5%86%99%E5%85%A5%20X%3D1%0A%20%20%20%20N1--xN2%3A%20%E5%90%8C%E6%AD%A5%E5%A4%B1%E8%B4%A5%EF%BC%88%E7%BD%91%E7%BB%9C%E6%96%AD%E5%BC%80%EF%BC%89%0A%0A%20%20%20%20alt%20%E9%80%89%E6%8B%A9%20C%EF%BC%88%E4%B8%80%E8%87%B4%E6%80%A7%EF%BC%89%E2%86%92%20%E6%94%BE%E5%BC%83%20A%0A%20%20%20%20%20%20%20%20Client-%3E%3EN2%3A%20%E8%AF%BB%E5%8F%96%20X%0A%20%20%20%20%20%20%20%20N2--%3E%3EClient%3A%20%E6%8B%92%E7%BB%9D%E6%9C%8D%E5%8A%A1%EF%BC%88%E6%95%B0%E6%8D%AE%E5%8F%AF%E8%83%BD%E4%B8%8D%E4%B8%80%E8%87%B4%EF%BC%89%0A%20%20%20%20%20%20%20%20Note%20over%20Client%3A%20CP%20%E7%B3%BB%E7%BB%9F%EF%BC%9A%E5%AE%81%E5%8F%AF%E4%B8%8D%E5%8F%AF%E7%94%A8%EF%BC%8C%E4%B9%9F%E8%A6%81%E4%BF%9D%E8%AF%81%E4%B8%80%E8%87%B4%0A%20%20%20%20else%20%E9%80%89%E6%8B%A9%20A%EF%BC%88%E5%8F%AF%E7%94%A8%E6%80%A7%EF%BC%89%E2%86%92%20%E6%94%BE%E5%BC%83%20C%0A%20%20%20%20%20%20%20%20Client-%3E%3EN2%3A%20%E8%AF%BB%E5%8F%96%20X%0A%20%20%20%20%20%20%20%20N2--%3E%3EClient%3A%20%E8%BF%94%E5%9B%9E%20X%3D0%EF%BC%88%E6%97%A7%E6%95%B0%E6%8D%AE%EF%BC%89%0A%20%20%20%20%20%20%20%20Note%20over%20Client%3A%20AP%20%E7%B3%BB%E7%BB%9F%EF%BC%9A%E5%AE%81%E5%8F%AF%E8%BF%94%E5%9B%9E%E6%97%A7%E6%95%B0%E6%8D%AE%EF%BC%8C%E4%B9%9F%E8%A6%81%E4%BF%9D%E8%AF%81%E5%8F%AF%E7%94%A8%0A%20%20%20%20end%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[e(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=d("p",null,[d("strong",null,"关键理解"),e("：在分布式环境中，网络分区（P）是不可避免的，所以实际上是在 C 和 A 之间做选择。")],-1)),t[5]||(t[5]=d("h4",{id:"实际系统的-cap-选择",tabindex:"-1"},[e("实际系统的 CAP 选择 "),d("a",{class:"header-anchor",href:"#实际系统的-cap-选择","aria-label":'Permalink to "实际系统的 CAP 选择"'},"​")],-1)),(r(),i(o,null,{default:a(()=>[l(A,{id:"mermaid-81",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20subgraph%20%22CP%20%E7%B3%BB%E7%BB%9F%EF%BC%88%E4%B8%80%E8%87%B4%E6%80%A7%E4%BC%98%E5%85%88%EF%BC%89%22%0A%20%20%20%20%20%20%20%20CP1%5B%22ZooKeeper%22%5D%0A%20%20%20%20%20%20%20%20CP2%5B%22Consul%22%5D%0A%20%20%20%20%20%20%20%20CP3%5B%22etcd%22%5D%0A%20%20%20%20%20%20%20%20CP4%5B%22HBase%22%5D%0A%20%20%20%20%20%20%20%20CP5%5B%22MongoDB%EF%BC%88%E9%BB%98%E8%AE%A4%EF%BC%89%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22AP%20%E7%B3%BB%E7%BB%9F%EF%BC%88%E5%8F%AF%E7%94%A8%E6%80%A7%E4%BC%98%E5%85%88%EF%BC%89%22%0A%20%20%20%20%20%20%20%20AP1%5B%22Eureka%22%5D%0A%20%20%20%20%20%20%20%20AP2%5B%22Cassandra%22%5D%0A%20%20%20%20%20%20%20%20AP3%5B%22DynamoDB%22%5D%0A%20%20%20%20%20%20%20%20AP4%5B%22CouchDB%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22%E5%8F%AF%E5%88%87%E6%8D%A2%22%0A%20%20%20%20%20%20%20%20SW1%5B%22Nacos%EF%BC%88AP%2FCP%20%E5%8F%AF%E5%88%87%E6%8D%A2%EF%BC%89%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20style%20CP1%20fill%3A%23e8f5e9%0A%20%20%20%20style%20CP2%20fill%3A%23e8f5e9%0A%20%20%20%20style%20CP3%20fill%3A%23e8f5e9%0A%20%20%20%20style%20AP1%20fill%3A%23fff3e0%0A%20%20%20%20style%20AP2%20fill%3A%23fff3e0%0A%20%20%20%20style%20SW1%20fill%3A%23e1f5fe%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[e(" Loading... ",-1)])]),_:1})),t[6]||(t[6]=E('<table tabindex="0"><thead><tr><th>系统</th><th>CAP 选择</th><th>原因</th></tr></thead><tbody><tr><td>ZooKeeper</td><td>CP</td><td>ZAB 协议保证强一致性，Leader 宕机时短暂不可用</td></tr><tr><td>Consul</td><td>CP</td><td>Raft 协议保证一致性，适合服务发现场景</td></tr><tr><td>etcd</td><td>CP</td><td>Raft 协议，K8s 的核心存储</td></tr><tr><td>Eureka</td><td>AP</td><td>自我保护机制，网络分区时仍返回可能过期的服务列表</td></tr><tr><td>Nacos</td><td>AP/CP</td><td>临时实例用 AP（Distro 协议），持久实例用 CP（Raft 协议）</td></tr><tr><td>Redis Cluster</td><td>AP</td><td>异步复制，主节点故障时可能丢失少量数据</td></tr></tbody></table><blockquote><p><strong>面试重点</strong>：不要死记硬背 CAP 分类，要理解每个系统为什么做出这样的选择。比如注册中心选 CP 还是 AP，取决于你能否容忍短暂的服务列表不一致。</p></blockquote><h3 id="二、cap-的常见误区" tabindex="-1">二、CAP 的常见误区 <a class="header-anchor" href="#二、cap-的常见误区" aria-label="Permalink to &quot;二、CAP 的常见误区&quot;">​</a></h3><table tabindex="0"><thead><tr><th>误区</th><th>正确理解</th></tr></thead><tbody><tr><td>CAP 是静态的三选二</td><td>CAP 的选择可以是动态的，同一系统在不同场景下可以做不同选择</td></tr><tr><td>放弃 C 就是完全不一致</td><td>放弃的是强一致性，通常仍保证最终一致性</td></tr><tr><td>放弃 A 就是完全不可用</td><td>放弃的是 100% 可用，通常只是部分节点短暂不可用</td></tr><tr><td>CA 系统存在</td><td>在分布式环境中 P 不可避免，CA 只存在于单机系统（如单机 MySQL）</td></tr></tbody></table><h3 id="三、base-理论" tabindex="-1">三、BASE 理论 <a class="header-anchor" href="#三、base-理论" aria-label="Permalink to &quot;三、BASE 理论&quot;">​</a></h3><p>BASE 是对 CAP 中 AP 方案的实践总结，是大规模互联网系统的设计指导思想。</p><table tabindex="0"><thead><tr><th>缩写</th><th>英文</th><th>含义</th><th>示例</th></tr></thead><tbody><tr><td>BA</td><td>Basically Available（基本可用）</td><td>系统出现故障时，允许损失部分功能，保证核心功能可用</td><td>电商大促时关闭推荐功能，保证下单功能</td></tr><tr><td>S</td><td>Soft State（软状态）</td><td>允许系统中的数据存在中间状态，不要求实时一致</td><td>订单状态&quot;支付中&quot;是一个中间状态</td></tr><tr><td>E</td><td>Eventually Consistent（最终一致性）</td><td>经过一段时间后，所有节点的数据最终达到一致</td><td>主从复制延迟后最终数据一致</td></tr></tbody></table>',7)),(r(),i(o,null,{default:a(()=>[l(A,{id:"mermaid-287",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20subgraph%20%22ACID%EF%BC%88%E5%BC%BA%E4%B8%80%E8%87%B4%E6%80%A7%EF%BC%89%22%0A%20%20%20%20%20%20%20%20A1%5B%22%E5%8E%9F%E5%AD%90%E6%80%A7%22%5D%20--%3E%20A2%5B%22%E4%B8%80%E8%87%B4%E6%80%A7%22%5D%0A%20%20%20%20%20%20%20%20A2%20--%3E%20A3%5B%22%E9%9A%94%E7%A6%BB%E6%80%A7%22%5D%0A%20%20%20%20%20%20%20%20A3%20--%3E%20A4%5B%22%E6%8C%81%E4%B9%85%E6%80%A7%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22BASE%EF%BC%88%E6%9C%80%E7%BB%88%E4%B8%80%E8%87%B4%E6%80%A7%EF%BC%89%22%0A%20%20%20%20%20%20%20%20B1%5B%22%E5%9F%BA%E6%9C%AC%E5%8F%AF%E7%94%A8%22%5D%20--%3E%20B2%5B%22%E8%BD%AF%E7%8A%B6%E6%80%81%22%5D%0A%20%20%20%20%20%20%20%20B2%20--%3E%20B3%5B%22%E6%9C%80%E7%BB%88%E4%B8%80%E8%87%B4%E6%80%A7%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20A4%20-.-%3E%7C%22%E5%88%86%E5%B8%83%E5%BC%8F%E5%9C%BA%E6%99%AF%E4%B8%8B%E7%9A%84%E6%9D%83%E8%A1%A1%22%7C%20B1%0A%0A%20%20%20%20style%20A1%20fill%3A%23e8f5e9%0A%20%20%20%20style%20B1%20fill%3A%23fff3e0%0A"})]),fallback:a(()=>[...t[2]||(t[2]=[e(" Loading... ",-1)])]),_:1})),t[7]||(t[7]=E('<h4 id="最终一致性的实现方式" tabindex="-1">最终一致性的实现方式 <a class="header-anchor" href="#最终一致性的实现方式" aria-label="Permalink to &quot;最终一致性的实现方式&quot;">​</a></h4><table tabindex="0"><thead><tr><th>方式</th><th>说明</th><th>典型场景</th></tr></thead><tbody><tr><td>读时修复（Read Repair）</td><td>读取时发现不一致，触发修复</td><td>Cassandra</td></tr><tr><td>写时修复（Write Repair）</td><td>写入时检测冲突并修复</td><td>DynamoDB</td></tr><tr><td>反熵（Anti-Entropy）</td><td>后台定期比对并同步数据</td><td>Cassandra Merkle Tree</td></tr><tr><td>异步复制</td><td>主节点写入后异步同步到从节点</td><td>MySQL 主从复制、Redis 主从</td></tr><tr><td>消息队列</td><td>通过消息中间件保证最终一致</td><td>订单系统 + 库存系统</td></tr></tbody></table><h2 id="代码示例" tabindex="-1">代码示例 <a class="header-anchor" href="#代码示例" aria-label="Permalink to &quot;代码示例&quot;">​</a></h2><p>CAP 和 BASE 是理论概念，没有直接的代码实现。但可以通过以下代码示例理解其应用：</p><blockquote><p>💻 分布式锁（CP 思想）：<a href="./../../../code-examples/05-distributed/distributed-examples/src/main/java/com/example/distributed/lock/DistributedLockCompare.java.html">DistributedLockCompare.java</a></p><p>💻 分布式事务（BASE 思想）：<a href="./../../../code-examples/05-distributed/distributed-examples/src/main/java/com/example/distributed/transaction/DistributedTransactionDemo.java.html">DistributedTransactionDemo.java</a></p></blockquote><h2 id="常见面试题" tabindex="-1">常见面试题 <a class="header-anchor" href="#常见面试题" aria-label="Permalink to &quot;常见面试题&quot;">​</a></h2><h3 id="q1-请解释-cap-理论-为什么是三选二" tabindex="-1">Q1: 请解释 CAP 理论，为什么是三选二？ <a class="header-anchor" href="#q1-请解释-cap-理论-为什么是三选二" aria-label="Permalink to &quot;Q1: 请解释 CAP 理论，为什么是三选二？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥🔥🔥</p><p><strong>答题思路</strong>：</p><ol><li>先解释 C、A、P 三个要素的含义</li><li>用网络分区场景说明为什么不能同时满足</li><li>举实际系统的例子</li></ol><p><strong>标准答案</strong>：</p><p>CAP 理论指出分布式系统不可能同时满足一致性（C）、可用性（A）和分区容错性（P）。在分布式环境中网络分区不可避免，所以实际是在 C 和 A 之间选择。当网络分区发生时，如果要保证一致性（CP），就必须拒绝部分请求直到数据同步完成，牺牲可用性；如果要保证可用性（AP），就必须允许返回可能不一致的数据。例如 ZooKeeper/Consul 选择 CP，Leader 宕机时短暂不可用；Eureka 选择 AP，网络分区时仍返回可能过期的服务列表。</p><p><strong>深入追问</strong>：</p><ul><li>Nacos 是 CP 还是 AP？（可切换，临时实例 AP，持久实例 CP）</li><li>为什么说 CA 系统在分布式环境中不存在？</li><li>CAP 中的 C 和 ACID 中的 C 是一回事吗？（不是，CAP 的 C 是线性一致性，ACID 的 C 是事务一致性）</li></ul><p><strong>易错点</strong>：</p><ul><li>把 CAP 理解为静态的三选二，实际上可以根据场景动态选择</li><li>认为放弃 C 就是完全不一致，实际上通常是最终一致性</li></ul><h3 id="q2-什么是-base-理论-和-acid-有什么区别" tabindex="-1">Q2: 什么是 BASE 理论？和 ACID 有什么区别？ <a class="header-anchor" href="#q2-什么是-base-理论-和-acid-有什么区别" aria-label="Permalink to &quot;Q2: 什么是 BASE 理论？和 ACID 有什么区别？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥🔥🔥</p><p><strong>答题思路</strong>：</p><ol><li>解释 BASE 三个要素</li><li>与 ACID 对比</li><li>说明适用场景</li></ol><p><strong>标准答案</strong>：</p><p>BASE 是 Basically Available（基本可用）、Soft State（软状态）、Eventually Consistent（最终一致性）的缩写，是对 CAP 中 AP 方案的实践总结。与 ACID 追求强一致性不同，BASE 允许系统在一定时间内存在不一致的中间状态，最终达到一致。ACID 适用于单机数据库事务，BASE 适用于分布式系统。例如电商下单后，订单服务和库存服务之间通过消息队列保证最终一致性，而不是用分布式事务保证强一致性。</p><p><strong>深入追问</strong>：</p><ul><li>最终一致性的&quot;最终&quot;是多久？（取决于系统设计，可能是毫秒级到秒级）</li><li>有哪些实现最终一致性的方式？（消息队列、异步复制、读时修复、反熵）</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://www.infoq.com/articles/cap-twelve-years-later-how-the-rules-have-changed/" target="_blank" rel="noreferrer">Brewer&#39;s CAP Theorem (2000)</a></li><li><a href="https://groups.csail.mit.edu/tds/papers/Gilbert/Brewer2.pdf" target="_blank" rel="noreferrer">CAP Theorem Proof (Gilbert &amp; Lynch, 2002)</a></li></ul>',26))])}const f=s(C,[["render",h]]);export{m as __pageData,f as default};
